$_MODULE['<{opartdevis}prestashop>faq_a4be6984c377fe11d8a50313ed0b6163'] = 'Wie kann die Möglichkeit, einen Warenkorb in ein Angebot umzuwandeln, ';
$_MODULE['<{opartdevis}prestashop>faq_d08042046897d46e889dfdd43f805942'] = 'Um die Nutzung des Angebotsmoduls auf eine bestimmte Kundengruppe zu beschränken, müssen Sie zum Abschnitt „Prestashop-Einstellungen -> Kunden -> Gruppen“ gehen.';
$_MODULE['<{opartdevis}prestashop>faq_81eb3506c5871f920c9c555fdcb5c6d2'] = 'Klicken Sie dann auf die Gruppe, die Sie bearbeiten möchten.';
$_MODULE['<{opartdevis}prestashop>faq_b8b9897a243fd6274f757bdb8714d178'] = 'Für jede Kundengruppe können Sie die für Ihren Shop verfügbaren Module aktivieren oder deaktivieren.';
$_MODULE['<{opartdevis}prestashop>faq_0f7331852c7e452d4171455c8a4e1c37'] = ' Grundsätzlich stehen für alle Kundengruppen freigeschaltete Module zur Verfügung. Wenn Sie also die Nutzung des Angebotsmoduls auf bestimmte Kundengruppen beschränken möchten, müssen Sie die Gruppen ändern, die keinen Zugriff mehr haben, und das Modul für diese Gruppe deaktivieren.';
$_MODULE['<{opartdevis}prestashop>faq_158d10181e6aa7b90f114de6f709b086'] = 'Das Modul erscheint nicht auf der Kundenkontoseite';
$_MODULE['<{opartdevis}prestashop>faq_7f7af2c26005a6ec38d2566882e360d9'] = 'Bei klassischen Themes ist keine Bedienung erforderlich, das Modul ist standardmäßig vorhanden.';
$_MODULE['<{opartdevis}prestashop>faq_b3a7ea03bb43ac097833d7a3ba8bfe02'] = ' Wenn Sie das WareHouse-Theme verwenden';
$_MODULE['<{opartdevis}prestashop>faq_29c3ce7917dfc127554aaa97e88730aa'] = 'Abhängig von der Version Ihres Themes ist es möglich, dass das Modul nicht im verfügbaren Menü im Kundenkonto vorhanden ist';
$_MODULE['<{opartdevis}prestashop>faq_1db3b074f66e527ba23338d9dda8900b'] = 'Wenn ja, fügen Sie den Hook-Punkt zum Thema hinzu. Dazu müssen Sie die Datei „page.tpl“ unter folgendem Pfad ändern: themes/warehouse/templates/customer/page.tpl';
$_MODULE['<{opartdevis}prestashop>faq_ab5d64a2a866543de4d9173eae8f2378'] = 'Um diesen Zusatz vorzunehmen, müssen Sie daher Zugriff auf Ihr FTP haben.';
$_MODULE['<{opartdevis}prestashop>faq_f8c09d653182a9ec90ec12c16203e1a8'] = ' In der Datei „page.tpl“; Sie müssen diese Zeile hinzufügen:';
$_MODULE['<{opartdevis}prestashop>faq_947b0956b66488e0bab2a11dcad0b99d'] = ' Wie kann es passieren, dass der Kunde das Angebot nicht mehr ändern kann?';
$_MODULE['<{opartdevis}prestashop>faq_1d8dbb9db536520377e98621c6c35ed4'] = ' Ihre Kunden können die Angebote nur ändern, wenn sie nicht von Ihnen im Backoffice validiert werden.';
$_MODULE['<{opartdevis}prestashop>faq_159c6c34417ecc7c8b119f9d9b5917b5'] = ' Solange das Angebot nicht validiert ist, geht das Modul davon aus, dass Kunden ihre Anfrage noch ändern und daher Änderungen am Angebot vornehmen können';
$_MODULE['<{opartdevis}prestashop>faq_91264995bb0689fd83667d9e67f14901'] = ' Nach der Validierung durch Sie geht das Modul davon aus, dass es sich um Ihr Angebot handelt. Daher ändert sich das Gültigkeitsdatum nicht mehr und tritt ab dem Zeitpunkt der Validierung in Kraft. Das Datum, die Preise sowie der Inhalt des Angebots sind dann nicht mehr veränderbar';
$_MODULE['<{opartdevis}prestashop>faq_f4e93a11722bcab1be8b7e62d98635d8'] = 'Wie kann man die Versandkosten manuell ändern, ohne die vorab registrierten Transportregeln zu berücksichtigen?';
$_MODULE['<{opartdevis}prestashop>faq_5706be616ccfc10805ee59c73d20cf9f'] = 'Standardmäßig verwendet das Modul vorregistrierte Spediteure und ermöglicht es Ihnen nicht, Versandkosten manuell zum Angebot hinzuzufügen.';
$_MODULE['<{opartdevis}prestashop>faq_5bdb477155797d69ee77e56680f5b67d'] = 'Wenn Sie es wünschen, können wir jedoch eine spezielle Entwicklung an Ihrem Modul vornehmen, so dass es die manuelle Hinzurechnung von Versandkosten zulässt.';
